func solve(nums []int64) bool {
    n := len(nums)
    if n < 3 {
        return false
    }

    // Find p such that nums[0...p] is strictly increasing
    p := 0
    for i := 1; i < n; i++ {
        if nums[i] <= nums[i-1] {
            p = i - 1
            break
        }
    }

    // Find q such that nums[p...q] is strictly decreasing
    q := p + 1
    for i := q + 1; i < n; i++ {
        if nums[i] >= nums[i-1] {
            q = i - 1
            break
        }
    }

    // Check if nums[q...n-1] is strictly increasing
    for i := q + 1; i < n; i++ {
        if nums[i] <= nums[i-1] {
            return false
        }
    }

    return true
}
